mapper.select:
select t1.*
from esg.tb_emergency_response_training_result t1
where t1.write_year = #{writeYear}
   and t1.doc_type = #{docType}
   and t1.doc_no = #{docNo}
   and t1.comp_id = #{compId}
order by t1.action_dt desc

mapper.update:
update esg.tb_emergency_response_training_result set
    action_nm = #{actionNm},
    action_location = #{actionLocation},
    action_content = #{actionContent},
    action_result = #{actionResult},
    target_time = #{targetTime},
    measurement_time = #{measurementTime},
    observation_actual_behavior = #{observationActualBehavior},
    remark = #{remark},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and doc_seq = #{docSeq}
    and comp_id = #{compId}

update esg.tb_emergency_response_training_result set
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and doc_seq = #{docSeq}
    and comp_id = #{compId}
